body.script:
    // 2026년 기준 기준중위소득 및 가구원수별 최저생계비 반영 계산 로직
    function calculateRehab() {
      const debtInput = document.getElementById('totalDebt');
      const incomeInput = document.getElementById('monthlyIncome');
      const familyInput = document.getElementById('householdSize');
      const assetInput = document.getElementById('assetValue');
      const regionInput = document.getElementById('regionType');

      const debt = parseFloat(debtInput.value) || 0;
      const income = parseFloat(incomeInput.value) || 0;
      const family = parseInt(familyInput.value) || 1;
      const assets = parseFloat(assetInput.value) || 0;

      if (debt <= 0 || income <= 0) {
        document.getElementById('resultStatus').innerText = "올바른 총 채무액과 월 소득을 입력해 주십시오.";
        return;
      }

      // 2026년 기준 가구수별 최저 생계비 설정 (기준 중위소득의 약 60%)
      const livingCosts = {
        1: 1440000,
        2: 2380000,
        3: 3060000,
        4: 3720000
      };

      const minLivingCost = livingCosts[family] || (3720000 + (family - 4) * 600000);
      let expectedMonthlyPayment = income - minLivingCost;

      let statusText = "";
      let finalMonthly = 0;
      let totalRepay = 0;
      let writeOffRate = 0;

      if (income <= minLivingCost) {
        statusText = "월 소득이 법정 최저 생계비보다 적습니다. 추가적인 급여 증가 요소를 증빙하거나 특별 면책 사유를 구성하여 상담을 진행해야 합니다.";
        finalMonthly = 0;
      } else if (assets >= debt) {
        statusText = "보유하신 재산의 가치가 총 채무액보다 큽니다. 청산가치 보장의 원칙에 따라 회생 제도 이용이 불가할 수 있으니 재산 산정 재검토가 권장됩니다.";
        finalMonthly = 0;
      } else {
        statusText = "회생 요건을 갖추신 상태입니다. 다만 재신청의 경우 법원의 보정 권고가 통상적인 수준보다 까다로울 수 있으므로 세밀한 준비가 요구됩니다.";
        finalMonthly = Math.max(expectedMonthlyPayment, 150000); // 법원 최소 변제 권고선 보정
        totalRepay = finalMonthly * 36;
        if (totalRepay > debt) {
          totalRepay = debt;
        }
        writeOffRate = ((debt - totalRepay) / debt) * 100;
        if (writeOffRate < 0) writeOffRate = 0;
      }

      document.getElementById('resultLivingCost').innerText = minLivingCost.toLocaleString() + " 원";
      document.getElementById('resultMonthly').innerText = finalMonthly.toLocaleString() + " 원";
      document.getElementById('resultTotal').innerText = totalRepay.toLocaleString() + " 원";
      document.getElementById('resultRate').innerText = writeOffRate.toFixed(1) + " %";
      document.getElementById('resultStatus').innerText = statusText;
    }
